record.field:
if records:
    for emp in records:
        contract = env['hr.contract'].search([
            ('employee_id', '=', emp.id),
            ('state', '=', 'open')
        ], limit=1)

        if contract:
            vals = {}
            if contract.department_id and emp.department_id != contract.department_id:
                vals['department_id'] = contract.department_id.id
            if contract.job_id and emp.job_id != contract.job_id:
                vals['job_id'] = contract.job_id.id

            if vals:
                emp.write(vals)
